# Example task: Write a config package that loads server settings from environment variables with sensible defaults (Addr defaults to :8080, read timeout, max page size), parses durations and integers, validates the result and returns an error for invalid values.
```go
package config

import (
	"fmt"
	"os"
	"strconv"
	"time"
)

// Config holds server settings loaded from the environment with sane defaults.
type Config struct {
	Addr        string
	ReadTimeout time.Duration
	MaxPageSize int
}

func getenv(key, fallback string) string {
	if v := os.Getenv(key); v != "" {
		return v
	}
	return fallback
}

// Load reads configuration from environment variables, applying defaults for
// any that are unset, then validates the result.
func Load() (Config, error) {
	c := Config{
		Addr:        getenv("ADDR", ":8080"),
		ReadTimeout: 5 * time.Second,
		MaxPageSize: 100,
	}
	if s := os.Getenv("READ_TIMEOUT"); s != "" {
		d, err := time.ParseDuration(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid READ_TIMEOUT: %w", err)
		}
		c.ReadTimeout = d
	}
	if s := os.Getenv("MAX_PAGE_SIZE"); s != "" {
		n, err := strconv.Atoi(s)
		if err != nil {
			return Config{}, fmt.Errorf("invalid MAX_PAGE_SIZE: %w", err)
		}
		c.MaxPageSize = n
	}
	if err := c.Validate(); err != nil {
		return Config{}, err
	}
	return c, nil
}

// Validate reports whether the configuration is usable.
func (c Config) Validate() error {
	if c.Addr == "" {
		return fmt.Errorf("addr must not be empty")
	}
	if c.MaxPageSize <= 0 {
		return fmt.Errorf("max page size must be positive, got %d", c.MaxPageSize)
	}
	return nil
}
```
# Example task: Write a models package (domain types only, standard library only) defining MULTIPLE exported domain types in ONE file with JSON tags: an entity struct (ID, Title/Name, Status string; valid status from a fixed set) AND a separate Event struct {Type, TaskID string} for the event seam, plus an exported sentinel var ErrInvalid = errors.New and a (t Entity) Validate() error method wrapping ErrInvalid via fmt.Errorf on empty or invalid fields. EVERY type the file's spec names must exist here — other packages import and reference them (never omit the Event type).
```go
package models

import (
	"errors"
	"fmt"
)

// ErrInvalid is the sentinel wrapped by every validation failure.
var ErrInvalid = errors.New("invalid")

// Order is a domain entity with a lifecycle status.
type Order struct {
	ID     string `json:"id"`
	Status string `json:"status"`
}

// Event is a SEPARATE domain type in the SAME package — a package often holds
// more than one type; define EVERY type the spec lists, not just the first.
type Event struct {
	Type    string `json:"type"`
	OrderID string `json:"order_id"`
}

// Validate reports whether the order is well-formed, wrapping ErrInvalid.
func (o Order) Validate() error {
	if o.ID == "" {
		return fmt.Errorf("%w: id is required", ErrInvalid)
	}
	if o.Status != "open" && o.Status != "shipped" && o.Status != "closed" {
		return fmt.Errorf("%w: bad status %q", ErrInvalid, o.Status)
	}
	return nil
}
```

